1	'use strict';
2	// 명령 로직의 단일 소스. CLI(bin/aad.js)와 서버(server/serve.js)가 모두 여기를 호출한다.
3	// 여기 함수들은 콘솔 출력/exit을 하지 않고 "데이터"만 돌려준다 (CLI는 출력용으로 포장, 서버는 JSON으로).
4	
5	const fs = require('fs');
6	const path = require('path');
7	const crypto = require('crypto');
8	const { execFileSync } = require('child_process');
9	const matter = require('gray-matter');
10	
11	const paths = require('./paths');
12	const scanner = require('./scanner');
13	const canonical = require('./canonical');
14	const security = require('./security');
15	const diff = require('./diff');
16	const backup = require('./backup');
17	const transformInstr = require('./transform/instructions');
18	const transformAgent = require('./transform/agent');
19	const transformSkill = require('./transform/skill');
20	const telemetry = require('./telemetry');
21	const maintenance = require('./maintenance');
22	const synclog = require('./synclog');
23	const store = require('./store');
24	const registry = require('./registry');
25	const category = require('./category');
26	const search = require('./search');
27	const playground = require('./playground');
28	const projects = require('./projects');
29	
30	const CANON_ID = 'instr-global'; // 슬라이스: 글로벌 지시문 1개
31	
32	// PI 게이트에 걸렸음을 알리는 전용 에러 (호출자가 사용자 확인을 받게 함)
33	class PiGateError extends Error {
34	  constructor(detected, maskedLines) {
35	    super('PI_GATE');
36	    this.name = 'PiGateError';
37	    this.detected = detected;
38	    this.maskedLines = maskedLines;
39	  }
40	}
41	
42	// canonical 저장소에 변경 커밋 (로컬 전용). 미초기화/변경없음이면 조용히 넘어감.
43	function gitCommit(message) {
44	  const cwd = paths.canonicalRoot();
45	  try {
46	    execFileSync('git', ['rev-parse', '--is-inside-work-tree'], { cwd, stdio: 'ignore' });
47	  } catch {
48	    return;
49	  }
50	  try {
51	    execFileSync('git', ['add', '-A'], { cwd, stdio: 'ignore' });
52	    execFileSync('git', ['commit', '-m', message], { cwd, stdio: 'ignore' });
53	  } catch {
54	    /* 변경 없음 등 무시 */
55	  }
56	}
57	
58	// ================= 프로젝트 레지스트리 (T2) =================
59	// 로직은 cli/projects.js 단일 소스 — 여기는 위임 래퍼만 둔다.
60	
61	// 등록된 프로젝트 목록.
62	function projectsList() {
63	  return { projects: projects.list() };
64	}
65	
66	// 디스크 스캔(존재/이름만) — 후보 반환만 하고 자동 등록하지 않는다.
67	// root 미지정 시 모드별 기본 루트(더미=fixtures/projects, 실제=홈).
68	function projectsScan({ root } = {}) {
69	  const scanRoot = root || paths.projectScanDefaultRoot();
70	  const known = new Set(projects.list().map((p) => p.root));
71	  const candidates = projects
72	    .scan(scanRoot)
73	    .map((c) => ({ ...c, registered: known.has(c.root) }));
74	  return { root: scanRoot, candidates };
75	}
76	
77	// scan 결과(후보)를 레지스트리에 병합 — 사용자가 명시적으로 채택할 때만.
78	function projectsAdopt({ candidates } = {}) {
79	  return projects.adoptScan(candidates || []);
80	}
81	
82	function projectsAdd({ root }) {
83	  if (!root) throw new Error('root 경로가 필요합니다');
84	  return projects.add(root);
85	}
86	
87	function projectsRemove({ root }) {
88	  if (!root) throw new Error('root 경로가 필요합니다');
89	  return projects.remove(root);
90	}
91	
92	// 자동 발견 (UX-E1): 레지스트리(projects.json)가 비어 있을 때만 1회 스캔 후 자동 등록.
93	//  - 비어 있지 않으면 아무것도 하지 않는다("최초 1회만 스캔" 결정 유지, D27-③).
94	//  - 트리거는 사용자가 매트릭스 화면을 여는 것(자동 폴링 아님, D14 정합).
95	//  - 반환: { scanned:boolean, adopted:number }.
96	function projectsEnsureScanned() {
97	  if (projects.list().length > 0) return { scanned: false, adopted: 0 };
98	  const candidates = projects.scan(paths.projectScanDefaultRoot());
99	  const r = projects.adoptScan(candidates);
100	  return { scanned: true, adopted: r.adopted };
101	}
102	
103	// (보안 가드) 등록된 프로젝트만 pull 소스로 허용 — 임의 경로 읽기를 코드로 차단.
104	function requireRegisteredProject(root) {
105	  const abs = path.resolve(root);
106	  const found = projects.list().find((p) => p.root === abs);
107	  if (!found) throw new Error('등록되지 않은 프로젝트입니다 (먼저 aad projects add --root <path>): ' + abs);
108	  return abs;
109	}
110	
111	// 하이브리드: 존재만 (내용 안 읽음) + canonical 존재 여부
112	function overview() {
113	  const items = scanner.discoverInstructions().map((it) => ({
114	    id: it.id,
115	    type: it.type,
116	    scope: it.scope,
117	    tool: it.tool,
118	    name: it.name,
119	    exists: it.exists,
120	  }));
121	  // T2: 등록 프로젝트의 지시문은 "존재 여부만" 별도 필드로 노출.
122	  // items에 합치지 않는 이유: 지시문 트랙은 단일 canonical(instr-global) 구조라
123	  // 기존 소비자(status drift 계산·대시보드 카운트)가 items=글로벌 전제를 갖는다.
124	  // 프로젝트 지시문의 pull/push는 이번 범위 밖 — 표시 전용.
125	  const projectItems = scanner.discoverProjectInstructions().map((it) => ({
126	    id: it.id,
127	    type: it.type,
128	    scope: it.scope,
129	    projectRoot: it.projectRoot,
130	    tool: it.tool,
131	    name: it.name,
132	    exists: it.exists,
133	  }));
134	  const canon = canonical.read(CANON_ID);
135	  return {
136	    canonId: CANON_ID,
137	    canonicalExists: !!canon,
138	    source: canon ? canon.meta.source_tool : null,
139	    items,
140	    projectItems,
141	  };
142	}
143	
144	// 클릭 시: 특정 도구 배포본과 canonical의 drift (내용 읽기 — 사용자 동작)
145	function diffFor(tool) {
146	  if (!paths.TOOLS.includes(tool)) throw new Error('알 수 없는 도구: ' + tool);
147	  const canon = canonical.read(CANON_ID);
148	  if (!canon) return { canonicalExists: false };
149	  const target = paths.instructionPath(tool);
150	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
151	  const d = diff.lineDiff(canon.body, deployed);
152	  return {
153	    canonicalExists: true,
154	    tool,
155	    exists: fs.existsSync(target),
156	    targetPath: target,
157	    diff: d,
158	    hasChanges: diff.hasChanges(d),
159	  };
160	}
161	
162	// import: 도구 지시문 → canonical. PI 감지 시 piAck 없으면 PiGateError를 던진다.
163	function pull({ from, piAck }) {
164	  if (!paths.TOOLS.includes(from)) throw new Error('알 수 없는 도구: ' + from);
165	  const item = scanner.discoverInstructions().find((i) => i.tool === from);
166	  if (!item.exists) throw new Error(`${from}의 지시문 파일이 없습니다: ${item.path}`);
167	
168	  let { text, pi } = scanner.readItemContent(item);
169	  if (pi.length > 0) {
170	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
171	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
172	    if (piAck === 'mask') text = security.mask(text);
173	    // 'proceed' → 그대로
174	  }
175	  const meta = canonical.write(CANON_ID, text, { sourceTool: from });
176	  gitCommit(`pull: ${from} → canonical (${CANON_ID})`);
177	  return { imported: true, meta, piHandled: pi.length ? piAck : null };
178	}
179	
180	// sync: canonical → 도구. apply=false면 미리보기(diff)만, true면 백업 후 쓰기.
181	function push({ to, apply }) {
182	  if (!paths.TOOLS.includes(to)) throw new Error('알 수 없는 도구: ' + to);
183	  const canon = canonical.read(CANON_ID);
184	  if (!canon) throw new Error('canonical이 비어 있습니다. 먼저 pull 하세요.');
185	
186	  const rendered = transformInstr.render(canon.body, to);
187	  const deployed = fs.existsSync(rendered.targetPath)
188	    ? fs.readFileSync(rendered.targetPath, 'utf8')
189	    : '';
190	  const d = diff.lineDiff(deployed, rendered.body);
191	
192	  if (!apply) {
193	    return {
194	      applied: false,
195	      to,
196	      targetPath: rendered.targetPath,
197	      diff: d,
198	      hasChanges: diff.hasChanges(d),
199	      losses: rendered.losses,
200	    };
201	  }
202	  const backupPath = backup.backupFile(rendered.targetPath, to, { kind: 'instruction', item: CANON_ID });
203	  fs.mkdirSync(path.dirname(rendered.targetPath), { recursive: true });
204	  fs.writeFileSync(rendered.targetPath, rendered.body);
205	  synclog.recordPush(to);
206	  return { applied: true, to, targetPath: rendered.targetPath, backupPath, losses: rendered.losses };
207	}
208	
209	// ================= agent 트랙 =================
210	
211	// 개요: canonical agent 목록 + 도구별 발견(존재) + 비표준 파일
212	function agentOverview() {
213	  const disc = scanner.discoverAgents();
214	  return {
215	    canonicalAgents: canonical.listAgents().map((a) => ({
216	      id: a.id,
217	      name: a.name,
218	      tools: a.tools || [],
219	      source_tool: a.source_tool,
220	      tags: a.tags || [],
221	      // T2: 프로젝트에서 pull한 항목 표시 (글로벌 항목은 필드 없음 → JSON에서 생략됨)
222	      scope: a.scope,
223	      project_root: a.project_root,
224	    })),
225	    toolAgents: disc.agents, // {tool, name, ...}
226	    nonStandard: disc.nonStandard,
227	  };
228	}
229	
230	// import: 도구의 agent 파일 → canonical 중립 스키마. PI 게이트 적용.
231	// T2: projectRoot가 있으면 "등록된 프로젝트"의 agent 폴더에서 읽는다 (미등록 경로는 거부).
232	function agentPull({ from, name, piAck, projectRoot }) {
233	  if (!paths.TOOLS.includes(from)) throw new Error('알 수 없는 도구: ' + from);
234	  const projRoot = projectRoot ? requireRegisteredProject(projectRoot) : null;
235	  const filePath = projRoot
236	    ? path.join(paths.projectAgentDir(projRoot, from), name + paths.agentExt(from))
237	    : paths.agentPath(from, name);
238	  if (!fs.existsSync(filePath)) throw new Error(`agent 파일이 없습니다: ${filePath}`);
239	
240	  let { text, pi } = scanner.readItemContent({ path: filePath });
241	  if (pi.length > 0) {
242	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
243	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
244	    if (piAck === 'mask') text = security.mask(text);
245	  }
246	  const neutral = transformAgent.parse(text, from, name);
247	  // 프로젝트 출처 표기 — writeAgent는 중립 스키마를 spread로 보존하므로 여기서 필드만 더한다.
248	  if (projRoot) {
249	    neutral.scope = 'project';
250	    neutral.project_root = projRoot;
251	  } else {
252	    neutral.scope = 'global';
253	  }
254	  const record = canonical.writeAgent(neutral);
255	  gitCommit(`pull agent: ${projRoot ? projRoot + ':' : ''}${from}/${name} → canonical (${record.id})`);
256	  return { imported: true, agent: record, piHandled: pi.length ? piAck : null };
257	}
258	
259	// 미리보기: canonical agent → 특정 도구 렌더 결과(diff + 손실)
260	function agentDiff(id, to) {
261	  const neutral = canonical.readAgent(id);
262	  if (!neutral) return { canonicalExists: false };
263	  const rendered = transformAgent.render(neutral, to);
264	  const target = paths.agentPath(to, neutral.name);
265	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
266	  const d = diff.lineDiff(deployed, rendered.content);
267	  return {
268	    canonicalExists: true,
269	    to,
270	    targetPath: target,
271	    diff: d,
272	    hasChanges: diff.hasChanges(d),
273	    losses: rendered.losses,
274	  };
275	}
276	
277	// sync: canonical agent → 도구. apply=false면 미리보기, true면 백업 후 쓰기.
278	function agentPush({ id, to, apply }) {
279	  if (!paths.TOOLS.includes(to)) throw new Error('알 수 없는 도구: ' + to);
280	  const neutral = canonical.readAgent(id);
281	  if (!neutral) throw new Error('canonical에 해당 agent가 없습니다: ' + id);
282	  const rendered = transformAgent.render(neutral, to);
283	  const target = paths.agentPath(to, neutral.name);
284	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
285	  const d = diff.lineDiff(deployed, rendered.content);
286	
287	  if (!apply) {
288	    return { applied: false, to, targetPath: target, diff: d, hasChanges: diff.hasChanges(d), losses: rendered.losses };
289	  }
290	  const backupPath = backup.backupFile(target, to, { kind: 'agent', item: neutral.name });
291	  fs.mkdirSync(path.dirname(target), { recursive: true });
292	  fs.writeFileSync(target, rendered.content);
293	  synclog.recordPush(to);
294	  return { applied: true, to, targetPath: target, backupPath, losses: rendered.losses };
295	}
296	
297	// ================= skill 트랙 =================
298	
299	// 개요: canonical skill 목록 + 도구별 발견(존재). 비공식 소스는 official:false로 표시(D11).
300	function skillOverview() {
301	  const discovered = scanner.discoverSkills();
302	  return {
303	    canonicalSkills: canonical.listSkills().map((s) => ({
304	      id: s.id,
305	      name: s.name,
306	      source_tool: s.source_tool,
307	      official: s.official,
308	      tags: s.tags || [],
309	      // T2: 프로젝트에서 pull한 항목 표시 (글로벌 항목은 필드 없음 → JSON에서 생략됨)
310	      scope: s.scope,
311	      project_root: s.project_root,
312	    })),
313	    toolSkills: discovered, // {name, tool, source_id, official, shared, plugin, path}
314	    // 비공식 위치의 skill은 별도로 모아 사용자에게 알릴 수 있게 한다
315	    unofficial: discovered.filter((s) => s.official === false),
316	  };
317	}
318	
319	// import: 도구의 skill(SKILL.md) → canonical. PI 게이트 적용. name으로 첫 매칭 소스를 쓴다.
320	// T2: projectRoot가 있으면 "등록된 프로젝트"의 소스로 좁힌다 (글로벌이 목록 앞이라 기본 동작 불변).
321	function skillPull({ name, source_id, piAck, projectRoot }) {
322	  let matches = scanner.discoverSkills().filter((s) => s.name === name);
323	  if (!matches.length) throw new Error(`skill을 찾을 수 없습니다: ${name}`);
324	  if (projectRoot) {
325	    const projRoot = requireRegisteredProject(projectRoot);
326	    matches = matches.filter((s) => s.projectRoot === projRoot);
327	    if (!matches.length) throw new Error(`해당 프로젝트에 skill이 없습니다: ${name} (${projRoot})`);
328	  }
329	  // source_id가 주어지면 그 소스, 아니면 첫 매칭
330	  const item = source_id ? matches.find((s) => s.source_id === source_id) : matches[0];
331	  if (!item) throw new Error(`해당 소스에 skill이 없습니다: ${name} (${source_id})`);
332	
333	  let { text, pi } = scanner.readItemContent({ path: item.path });
334	  if (pi.length > 0) {
335	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
336	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
337	    if (piAck === 'mask') text = security.mask(text);
338	  }
339	  const meta = canonical.writeSkill(name, text, {
340	    source_id: item.source_id,
341	    source_tool: item.tool,
342	    official: item.official,
343	    // 프로젝트 출처 표기 — 글로벌 pull은 scope:'global' + project_root 제거(null)로 정리.
344	    scope: item.scope === 'project' ? 'project' : 'global',
345	    project_root: item.scope === 'project' ? item.projectRoot : null,
346	  });
347	  gitCommit(`pull skill: ${item.source_id}/${name} → canonical`);
348	  return { imported: true, skill: meta, unofficialSource: item.official === false, piHandled: pi.length ? piAck : null };
349	}
350	
351	// 미리보기: canonical skill → 특정 도구로 복사할 결과(diff)
352	function skillDiff(name, to) {
353	  const canon = canonical.readSkill(name);
354	  if (!canon) return { canonicalExists: false };
355	  const rendered = transformSkill.render(canon.body, name, to);
356	  const deployed = fs.existsSync(rendered.targetPath) ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
357	  const d = diff.lineDiff(deployed, rendered.content);
358	  return {
359	    canonicalExists: true,
360	    to,
361	    targetPath: rendered.targetPath,
362	    diff: d,
363	    hasChanges: diff.hasChanges(d),
364	    losses: rendered.losses,
365	  };
366	}
367	
368	// sync: canonical skill → 도구. apply=false면 미리보기, true면 백업 후 쓰기.
369	function skillPush({ name, to, apply }) {
370	  const canon = canonical.readSkill(name);
371	  if (!canon) throw new Error('canonical에 해당 skill이 없습니다: ' + name);
372	  const rendered = transformSkill.render(canon.body, name, to);
373	  const deployed = fs.existsSync(rendered.targetPath) ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
374	  const d = diff.lineDiff(deployed, rendered.content);
375	  if (!apply) {
376	    return { applied: false, to, targetPath: rendered.targetPath, diff: d, hasChanges: diff.hasChanges(d), losses: rendered.losses };
377	  }
378	  const backupPath = backup.backupFile(rendered.targetPath, to, { kind: 'skill', item: name });
379	  fs.mkdirSync(path.dirname(rendered.targetPath), { recursive: true });
380	  fs.writeFileSync(rendered.targetPath, rendered.content);
381	  synclog.recordPush(to);
382	  return { applied: true, to, targetPath: rendered.targetPath, backupPath, losses: rendered.losses };
383	}
384	
385	// ================= 한 번에 동기화(Sync) — UX-A =================
386	// 사용자가 "미등록 소스"에서 [Sync]를 명시적으로 누른 항목이므로 각 도구 사본의
387	// 내용을 읽어 비교해도 된다(D9: 클릭 시 읽기). 실제 쓰기는 syncApply만 하고,
388	// 그 쓰기는 전부 기존 pull/push 함수 경유 → PI 게이트·백업·synclog·gitCommit 자동 상속.
389	// 새 쓰기 경로는 만들지 않는다.
390	
391	function contentHash(text) {
392	  return crypto.createHash('sha256').update(text == null ? '' : text, 'utf8').digest('hex').slice(0, 12);
393	}
394	
395	// agent "내용 동일" 판정 = 비교 대상 필드만 정규화한 JSON 해시.
396	// syncPlan(agentSyncPlan)과 syncMatrix가 공유한다(단일 규칙).
397	function agentNeutralKey(n) {
398	  return contentHash(
399	    JSON.stringify({
400	      name: n.name || '',
401	      description: n.description || '',
402	      system_prompt: n.system_prompt || '',
403	      model: n.model || null,
404	      tools: [...(n.tools || [])].sort(),
405	    })
406	  );
407	}
408	
409	// skill 동기화의 "도구 슬롯" = push 대상과 대칭인 3개 위치.
410	//  - claude → ~/.claude/skills(claude-user)
411	//  - codex  → .agents/skills(shared-agents, discoverSkills에선 tool='shared')
412	//  - gemini → ~/.gemini/skills(gemini-user)
413	// discoverSkills가 돌려준 항목 중 위 공식 소스만 도구 슬롯에 매핑한다.
414	// (플러그인/비공식/프로젝트 소스는 baseCandidate가 아니라 notes로만 알린다.)
415	const SKILL_TOOL_SOURCE = { claude: 'claude-user', codex: 'shared-agents', gemini: 'gemini-user' };
416	
417	// (1) 동기화 계획 — 읽기 전용(디스크 쓰기 0). kind: 'skill'|'agent'.
418	function syncPlan({ kind, name }) {
419	  if (kind === 'skill') return skillSyncPlan(name);
420	  if (kind === 'agent') return agentSyncPlan(name);
421	  throw new Error('알 수 없는 kind: ' + kind + " ('skill'|'agent')");
422	}
423	
424	// skill: 도구별 SKILL.md 내용 해시로 그룹핑. canonical 동명 항목도 참고 정보로 포함.
425	function skillSyncPlan(name) {
426	  if (!name) throw new Error('name이 필요합니다');
427	  const discovered = scanner.discoverSkills().filter((s) => s.name === name);
428	  const canon = canonical.readSkill(name);
429	  const canonicalExists = !!canon;
430	  const canonicalHash = canonicalExists ? contentHash(canon.body) : null;
431	
432	  // 내용 → 그룹 번호(1부터). canonical 내용도 같은 사전에 넣어 "같은 그룹"이면 도구=canonical.
433	  const groupOf = new Map();
434	  let nextGroup = 0;
435	  function assignGroup(h) {
436	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
437	    return groupOf.get(h);
438	  }
439	  if (canonicalExists) assignGroup(canonicalHash);
440	
441	  const tools = paths.TOOLS.map((tool) => {
442	    const sourceId = SKILL_TOOL_SOURCE[tool];
443	    // 이 도구 슬롯(공식 push 대상)에 실제로 발견된 skill
444	    const official = discovered.find((s) => s.source_id === sourceId && s.scope !== 'project');
445	    const notes = [];
446	    // 같은 이름이 비공식/플러그인/프로젝트 위치에도 있으면 특이사항으로 알린다.
447	    for (const s of discovered) {
448	      if (s.source_id === sourceId && s.scope !== 'project') continue;
449	      if (s.official === false) notes.push(`비공식 위치에도 존재: ${s.path}`);
450	      else if (s.plugin) notes.push(`플러그인 위치에도 존재: ${s.path}`);
451	      else if (s.scope === 'project') notes.push(`프로젝트 스코프에도 존재(@${s.projectRoot}): ${s.path}`);
452	      else if (SKILL_TOOL_SOURCE[tool] !== s.source_id) {
453	        // 다른 도구 슬롯의 것 — 여기서는 건너뜀(각 도구 항목에서 다룸)
454	      }
455	    }
456	    if (!official) {
457	      return { tool, exists: false, sourceId, official: true, group: null, notes };
458	    }
459	    const { text } = scanner.readItemContent({ path: official.path });
460	    const group = assignGroup(contentHash(text));
461	    return {
462	      tool,
463	      exists: true,
464	      sourceId: official.source_id,
465	      official: official.official !== false,
466	      scope: official.scope || 'global',
467	      group,
468	      notes,
469	    };
470	  });
471	
472	  const baseCandidates = tools.filter((t) => t.exists).map((t) => t.tool);
473	  return {
474	    kind: 'skill',
475	    name,
476	    canonicalExists,
477	    canonicalGroup: canonicalExists ? groupOf.get(canonicalHash) : null,
478	    tools,
479	    groups: groupOf.size,
480	    baseCandidates,
481	    // 스킬은 도구 간 변환 손실이 없다(SKILL.md 복사) → perBaseLosses는 빈 요약.
482	    perBaseLosses: Object.fromEntries(baseCandidates.map((t) => [t, {}])),
483	  };
484	}
