486	// agent: 도구별 파일 파싱(transform 재사용) 후 중립 스키마 비교 + 기준별 변환 손실.
487	function agentSyncPlan(name) {
488	  if (!name) throw new Error('name이 필요합니다');
489	  const id = 'agent-' + name;
490	  const disc = scanner.discoverAgents().agents.filter((a) => a.name === name && a.scope !== 'project');
491	  const canonNeutral = canonical.readAgent(id);
492	  const canonicalExists = !!canonNeutral;
493	
494	  // 중립 스키마의 "내용 동일" 판정은 agentNeutralKey(모듈 공유)로 위임.
495	  const neutralKey = agentNeutralKey;
496	  const groupOf = new Map();
497	  let nextGroup = 0;
498	  function assignGroup(h) {
499	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
500	    return groupOf.get(h);
501	  }
502	  if (canonicalExists) assignGroup(neutralKey(canonNeutral));
503	
504	  // 각 도구별로 파싱한 중립 스키마를 담아둔다(perBaseLosses 계산에 재사용).
505	  const parsedByTool = {};
506	  const tools = paths.TOOLS.map((tool) => {
507	    const found = disc.find((a) => a.tool === tool);
508	    const notes = [];
509	    if (!found) {
510	      // Codex는 에이전트별 tools 필드가 없다는 구조적 특이사항을 미리 알린다.
511	      if (tool === 'codex') notes.push('codex는 에이전트별 tools 필드가 없음 → tools는 codex로 내보낼 때 손실');
512	      return { tool, exists: false, group: null, notes };
513	    }
514	    const { text } = scanner.readItemContent({ path: found.path });
515	    const neutral = transformAgent.parse(text, tool, name);
516	    parsedByTool[tool] = neutral;
517	    const group = assignGroup(neutralKey(neutral));
518	    if (tool === 'codex') notes.push('codex 파일은 tools 필드가 없어 tools 정보가 없음(중립 스키마 tools=[])');
519	    if (neutral.source_notes) notes.push(neutral.source_notes);
520	    return { tool, exists: true, scope: found.scope || 'global', group, notes };
521	  });
522	
523	  const baseCandidates = tools.filter((t) => t.exists).map((t) => t.tool);
524	  // 각 후보를 기준으로 삼았을 때, 다른 도구로 render 시 생기는 손실 요약.
525	  const perBaseLosses = {};
526	  for (const base of baseCandidates) {
527	    const neutral = parsedByTool[base];
528	    const losses = {};
529	    for (const target of paths.TOOLS) {
530	      if (target === base) continue;
531	      losses[target] = transformAgent.render(neutral, target).losses;
532	    }
533	    perBaseLosses[base] = losses;
534	  }
535	
536	  return {
537	    kind: 'agent',
538	    name,
539	    canonicalExists,
540	    canonicalGroup: canonicalExists ? groupOf.get(neutralKey(canonNeutral)) : null,
541	    tools,
542	    groups: groupOf.size,
543	    baseCandidates,
544	    perBaseLosses,
545	  };
546	}
