548	// (2) 동기화 실행 — pull(기준→canonical) + push(나머지 도구, 내용 다르거나 없으면).
549	//  모든 쓰기는 기존 skillPull/agentPull/skillPush/agentPush 경유.
550	//  PI 감지 시 pull이 PiGateError를 던지며, 여기서 잡지 않고 그대로 전파(서버 409).
551	function syncApply({ kind, name, baseTool, sourceId, piAck }) {
552	  if (kind !== 'skill' && kind !== 'agent') throw new Error("알 수 없는 kind: " + kind + " ('skill'|'agent')");
553	  if (!name) throw new Error('name이 필요합니다');
554	  if (!paths.TOOLS.includes(baseTool)) throw new Error('기준 도구가 올바르지 않습니다(baseTool): ' + baseTool);
555	
556	  const plan = syncPlan({ kind, name });
557	  const baseSlot = plan.tools.find((t) => t.tool === baseTool);
558	  if (!baseSlot || !baseSlot.exists) {
559	    throw new Error(`기준 도구(${baseTool})에 ${kind} "${name}"가 없습니다. baseCandidates: [${plan.baseCandidates.join(', ')}]`);
560	  }
561	
562	  // 1) pull: 기준 도구 → canonical (기존 함수 재사용 — PI 게이트/gitCommit 상속)
563	  let pulled;
564	  if (kind === 'skill') {
565	    const r = skillPull({ name, source_id: sourceId || SKILL_TOOL_SOURCE[baseTool], piAck });
566	    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
567	    pulled = { from: baseTool, kind: 'skill', name, source_tool: r.skill.source_tool, unofficialSource: r.unofficialSource, piHandled: r.piHandled };
568	  } else {
569	    const r = agentPull({ from: baseTool, name, piAck });
570	    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
571	    pulled = { from: baseTool, kind: 'agent', id: r.agent.id, source_tool: r.agent.source_tool, piHandled: r.piHandled };
572	  }
573	
574	  // pull 이후의 canonical 내용으로 나머지 도구와 비교(기준 자신은 skip).
575	  const results = [];
576	  for (const tool of paths.TOOLS) {
577	    if (tool === baseTool) continue;
578	    try {
579	      const preview = kind === 'skill'
580	        ? skillPush({ name, to: tool, apply: false })
581	        : agentPush({ id: 'agent-' + name, to: tool, apply: false });
582	      if (!preview.hasChanges) {
583	        // canonical과 내용 동일(대상이 이미 존재하고 같음) → skip
584	        results.push({ tool, action: 'skipped_same', targetPath: preview.targetPath, losses: preview.losses });
585	        continue;
586	      }
587	      const applied = kind === 'skill'
588	        ? skillPush({ name, to: tool, apply: true })
589	        : agentPush({ id: 'agent-' + name, to: tool, apply: true });
590	      results.push({ tool, action: 'pushed', targetPath: applied.targetPath, backup: applied.backupPath, losses: applied.losses });
591	    } catch (e) {
592	      // 부분 실패: 중단하지 말고 도구별 결과로 기록.
593	      results.push({ tool, action: 'error', error: e.message });
594	    }
595	  }
596	  return { pulled, results };
597	}
