599	// ================= 동기화 매트릭스 (UX-E1) =================
600	// D27: 화면의 주인공 = "홈(~)과 각 프로젝트의 스킬·에이전트가 서로 동기화되어 있는가".
601	// 행 = (scope, name). scope = 'global'(전역 ~) 또는 등록 프로젝트 root.
602	// 각 행은 3개 도구(claude/codex/gemini) 슬롯의 존재/내용해시그룹 + 동기화 상태를 담는다.
603	//
604	// 읽기 전용(디스크 쓰기 0). 로컬 파일이므로 표 로드 시 그대로 읽어 해시 계산(캐시 불필요, D27-④).
605	// 파일 읽기 실패는 "행 단위 error"로 우아하게 표면화하고 전체는 계속 계산한다(D26-② 우아한 실패).
606	
607	// scope 라벨: 전역은 '전역(~)', 프로젝트는 '폴더명 (전체경로)'.
608	function scopeLabelFor(scope) {
609	  if (scope === 'global') return '전역(~)';
610	  return path.basename(scope) + ' (' + scope + ')';
611	}
612	
613	// canonical 메타의 동명 항목 태그를 우선, 없으면 파일 frontmatter의 tags(있을 때만).
614	function skillTagsFor(name, fallbackText) {
615	  const canon = canonical.readSkill(name);
616	  if (canon && Array.isArray(canon.meta.tags) && canon.meta.tags.length) return canon.meta.tags;
617	  if (fallbackText != null) {
618	    try {
619	      const fm = matter(fallbackText).data || {};
620	      if (Array.isArray(fm.tags) && fm.tags.length) return fm.tags;
621	    } catch {
622	      /* frontmatter 파싱 실패 — 태그 없음으로 취급 */
623	    }
624	  }
625	  return [];
626	}
627	function agentTagsFor(name, fallbackNeutral) {
628	  const canon = canonical.readAgent('agent-' + name);
629	  if (canon && Array.isArray(canon.tags) && canon.tags.length) return canon.tags;
630	  if (fallbackNeutral && Array.isArray(fallbackNeutral.tags) && fallbackNeutral.tags.length) {
631	    return fallbackNeutral.tags;
632	  }
633	  return [];
634	}
635	
636	// 세 도구 슬롯의 group(내용 그룹 번호)으로 동기화 상태를 판정한다.
637	//  - synced : 3도구 모두 존재 + 같은 그룹
638	//  - drift  : 존재하는 것 중 서로 다른 그룹이 섞임(내용 다름)
639	//  - partial: 일부 도구에만 있지만 있는 것끼리는 동일
640	//  - single : 1곳만 존재
641	function syncStateOf(toolSlots) {
642	  const present = paths.TOOLS.map((t) => toolSlots[t]).filter((s) => s && s.exists && s.group != null);
643	  if (present.length === 0) return 'single'; // (이론상 매트릭스에 안 올라오지만 방어적으로)
644	  if (present.length === 1) return 'single';
645	  const groups = new Set(present.map((s) => s.group));
646	  if (groups.size > 1) return 'drift';
647	  // 그룹 1개(있는 것끼리 동일) → 3도구 모두면 synced, 일부면 partial
648	  return present.length === paths.TOOLS.length ? 'synced' : 'partial';
649	}
