651	// ── skill 매트릭스 ──
652	// scope 슬롯: global은 SKILL_TOOL_SOURCE(공식 push 대상)와 대칭.
653	//             project는 projectSkillSources(claude/shared/gemini)와 대칭.
654	// codex 열은 shared(.agents/skills) 소스를 매핑한다(push 대칭과 동일, syncPlan과 정합).
655	function skillMatrix() {
656	  const discovered = scanner.discoverSkills();
657	
658	  // 행 키 = scope|name. scope = 'global' | projectRoot.
659	  // 각 (scope,name)에 대해 도구 슬롯을 채운다.
660	  //  - global 슬롯 매핑: claude→claude-user, codex→shared-agents, gemini→gemini-user
661	  //  - project 슬롯 매핑: claude→claude-project, codex→shared-project, gemini→gemini-project
662	  const GLOBAL_SLOT = { claude: 'claude-user', codex: 'shared-agents', gemini: 'gemini-user' };
663	  const PROJECT_SLOT = { claude: 'claude-project', codex: 'shared-project', gemini: 'gemini-project' };
664	
665	  // rows[rowKey] = { scope, name, slotItem:{tool->discovered item} }
666	  const rows = new Map();
667	  function rowFor(scope, name) {
668	    const key = scope + '�' + name;
669	    if (!rows.has(key)) rows.set(key, { scope, name, slots: {} });
670	    return rows.get(key);
671	  }
672	  for (const s of discovered) {
673	    const scope = s.scope === 'project' ? s.projectRoot : 'global';
674	    const slotMap = scope === 'global' ? GLOBAL_SLOT : PROJECT_SLOT;
675	    // 이 항목이 어느 도구 열에 속하는지 = source_id로 역매핑.
676	    const tool = paths.TOOLS.find((t) => slotMap[t] === s.source_id);
677	    if (!tool) continue; // 플러그인/비공식/codex-native 등 도구 열 밖 소스는 매트릭스 슬롯에 넣지 않음
678	    const row = rowFor(scope, s.name);
679	    if (!row.slots[tool]) row.slots[tool] = s; // 첫 매칭만(중복 방지)
680	  }
681	
682	  return [...rows.values()].map((row) => buildSkillRow(row));
683	}
684	
685	function buildSkillRow(row) {
686	  const { scope, name } = row;
687	  const errors = [];
688	  // 행별 내용 해시 그룹(존재 사본만). canonical도 참고용으로 같은 사전에 넣는다.
689	  const groupOf = new Map();
690	  let nextGroup = 0;
691	  const assign = (h) => {
692	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
693	    return groupOf.get(h);
694	  };
695	  const canon = canonical.readSkill(name);
696	  const canonicalExists = !!canon;
697	  if (canonicalExists) assign(contentHash(canon.body));
698	
699	  let anyText = null;
700	  const tools = {};
701	  for (const tool of paths.TOOLS) {
702	    const item = row.slots[tool];
703	    if (!item) {
704	      tools[tool] = { exists: false, group: null };
705	      continue;
706	    }
707	    try {
708	      const { text } = scanner.readItemContent({ path: item.path });
709	      if (anyText == null) anyText = text;
710	      tools[tool] = { exists: true, group: assign(contentHash(text)) };
711	    } catch (e) {
712	      // 우아한 실패(D26): 이 도구 슬롯만 error, 나머지는 계속.
713	      tools[tool] = { exists: false, group: null, error: e.message };
714	      errors.push(tool + ': ' + e.message);
715	    }
716	  }
717	  return {
718	    scope,
719	    scopeLabel: scopeLabelFor(scope),
720	    name,
721	    tags: skillTagsFor(name, anyText),
722	    tools,
723	    groups: groupOf.size,
724	    syncState: syncStateOf(tools),
725	    canonicalExists,
726	    canonicalGroup: canonicalExists ? groupOf.get(contentHash(canon.body)) : null,
727	    ...(errors.length ? { error: errors.join(' | ') } : {}),
728	  };
729	}
