731	// ── agent 매트릭스 ──
732	// 도구별 파일을 파싱(transformAgent.parse)해 중립 스키마로 정규화 후 비교(syncPlan과 동일 규칙).
733	function agentMatrix() {
734	  const disc = scanner.discoverAgents().agents;
735	  // 행 키 = scope|name.
736	  const rows = new Map();
737	  function rowFor(scope, name) {
738	    const key = scope + '�' + name;
739	    if (!rows.has(key)) rows.set(key, { scope, name, slots: {} });
740	    return rows.get(key);
741	  }
742	  for (const a of disc) {
743	    const scope = a.scope === 'project' ? a.projectRoot : 'global';
744	    const row = rowFor(scope, a.name);
745	    if (!row.slots[a.tool]) row.slots[a.tool] = a; // 도구당 첫 파일
746	  }
747	  return [...rows.values()].map((row) => buildAgentRow(row));
748	}
749	
750	function buildAgentRow(row) {
751	  const { scope, name } = row;
752	  const errors = [];
753	  const groupOf = new Map();
754	  let nextGroup = 0;
755	  const assign = (h) => {
756	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
757	    return groupOf.get(h);
758	  };
759	  const canonNeutral = canonical.readAgent('agent-' + name);
760	  const canonicalExists = !!canonNeutral;
761	  if (canonicalExists) assign(agentNeutralKey(canonNeutral));
762	
763	  let firstNeutral = null;
764	  const tools = {};
765	  for (const tool of paths.TOOLS) {
766	    const item = row.slots[tool];
767	    if (!item) {
768	      tools[tool] = { exists: false, group: null };
769	      continue;
770	    }
771	    try {
772	      const { text } = scanner.readItemContent({ path: item.path });
773	      const neutral = transformAgent.parse(text, tool, name);
774	      if (firstNeutral == null) firstNeutral = neutral;
775	      tools[tool] = { exists: true, group: assign(agentNeutralKey(neutral)) };
776	    } catch (e) {
777	      tools[tool] = { exists: false, group: null, error: e.message };
778	      errors.push(tool + ': ' + e.message);
779	    }
780	  }
781	  return {
782	    scope,
783	    scopeLabel: scopeLabelFor(scope),
784	    name,
785	    tags: agentTagsFor(name, firstNeutral),
786	    tools,
787	    groups: groupOf.size,
788	    syncState: syncStateOf(tools),
789	    canonicalExists,
790	    canonicalGroup: canonicalExists ? groupOf.get(agentNeutralKey(canonNeutral)) : null,
791	    ...(errors.length ? { error: errors.join(' | ') } : {}),
792	  };
793	}
794	
795	// (공개) 동기화 매트릭스. kind: 'skill'|'agent'.
796	//  - 시작 시 projectsEnsureScanned()로 자동 발견(레지스트리 비었을 때만 1회 스캔+등록, D27-③).
797	//  - 반환: { kind, autoScan:{scanned,adopted}, rows:[...], counts:{synced,partial,drift,single} }.
