50	  // 기록하지 않는다. defaultsOverlay(있으면)는 그대로 보존한다.
51	  const src = Array.isArray(reg) ? { version: 1, registries: reg } : (reg || {});
52	  const data = {
53	    version: src.version || 1,
54	    registries: (src.registries || []).filter((r) => !r.official),
55	  };
56	  if (src.defaultsOverlay && typeof src.defaultsOverlay === 'object') data.defaultsOverlay = src.defaultsOverlay;
57	  const file = paths.registriesFile();
58	  fs.mkdirSync(path.dirname(file), { recursive: true });
59	  fs.writeFileSync(file, JSON.stringify(data, null, 2) + '\n', 'utf8');
60	  return file;
61	}
