63	// ── 기본(번들) 레지스트리 ────────────────────────────────────────────
64	// catalog/default-registries.json = 정적 번들(D16 철학). 절대 런타임에 쓰지 않는다.
65	// 없거나 깨져도 빈 배열로 폴백(사용자 것만 살아남는다).
66	function defaultRegistriesPath() {
67	  if (process.env.AAD_DEFAULT_REGISTRIES) return process.env.AAD_DEFAULT_REGISTRIES;
68	  // catalog.json과 같은 디렉토리에 둔다(catalogPath 기준).
69	  return path.join(path.dirname(paths.catalogPath()), 'default-registries.json');
