72	// v2(publishers[]→repos[]) 우선 파싱, v1(평면 registries[]) fallback.
73	// 반환: repo 단위로 평탄화한 배열(각 항목이 clone 대상 레지스트리 1개).
74	//   { id, name(owner/repo), url, branch, official, publisher, publisherSlug, skillCountCurated }
75	function loadDefaults() {
76	  const file = defaultRegistriesPath();
77	  if (!fs.existsSync(file)) return [];
78	  let data;
79	  try {
80	    data = JSON.parse(fs.readFileSync(file, 'utf8'));
81	  } catch {
82	    return [];
83	  }
84	  if (!data || typeof data !== 'object') return [];
85	
86	  // v2: publishers[] → repos[] 평탄화.
87	  if (Array.isArray(data.publishers)) {
88	    const out = [];
89	    for (const pub of data.publishers) {
90	      if (!pub || !Array.isArray(pub.repos)) continue;
91	      const publisher = pub.name || pub.slug || '';
92	      const publisherSlug = pub.slug || slugify(String(pub.id || pub.name || ''));
93	      for (const repo of pub.repos) {
94	        if (!repo || !repo.url || !repo.id) continue;
95	        out.push({
96	          id: String(repo.id),
97	          name: repo.name || ownerRepoOf(repo.url),
98	          url: String(repo.url),
99	          branch: repo.branch || 'main',
100	          official: true, // 기본은 항상 official
101	          publisher,
102	          publisherSlug,
103	          skillCountCurated:
104	            typeof repo.skillCountCurated === 'number' ? repo.skillCountCurated : null,
105	        });
106	      }
107	    }
108	    return out;
109	  }
110	
111	  // v1 fallback: 평면 registries[].
112	  if (Array.isArray(data.registries)) {
113	    return data.registries
114	      .filter((r) => r && r.url && r.id)
115	      .map((r) => ({
116	        id: String(r.id),
117	        name: r.name || ownerRepoOf(r.url),
118	        url: String(r.url),
119	        branch: r.branch || 'main',
120	        official: true,
121	      }));
122	  }
123	
124	  return [];
125	}
