174	// 휴리스틱 키워드 → skill-tags key. name+description 문자열에서 매칭.
175	// 단순·순수함수. skill-tags 10종 기준.
176	const TAG_KEYWORDS = {
177	  frontend: ['frontend', 'react', 'vue', 'css', 'tailwind', 'ui', 'ux', 'html', 'component', 'design system'],
178	  backend: ['backend', 'server', 'api', 'worker', 'serverless', 'edge function', 'runtime', 'microservice'],
179	  ecommerce: ['ecommerce', 'e-commerce', 'commerce', 'payment', 'checkout', 'stripe', 'shopify', 'cart', 'subscription'],
180	  app: ['app dev', 'mobile', 'flutter', 'react native', 'expo', 'android', 'ios', 'dart'],
181	  devops: ['devops', 'ci/cd', 'cicd', 'pipeline', 'terraform', 'infrastructure', 'deploy', 'kubernetes', 'docker', 'pulumi'],
182	  'ai-ml': ['ai', 'ml', 'machine learning', 'llm', 'langchain', 'model', 'transformer', 'huggingface', 'embedding', 'rag'],
183	  database: ['database', 'db', 'sql', 'postgres', 'postgresql', 'mysql', 'mongodb', 'redis', 'prisma', 'orm', 'migration', 'firestore'],
184	  security: ['security', 'secure', 'auth', 'authentication', 'authorization', 'oauth', 'sso', 'mfa', 'encryption', 'clerk', 'auth0'],
185	  testing: ['test', 'testing', 'monitor', 'monitoring', 'observability', 'tracing', 'logging', 'sentry', 'datadog', 'e2e'],
186	  docs: ['docs', 'documentation', 'design', 'figma', 'notion', 'diagram', 'writing'],
187	};
