233	// URL을 안정적인 슬러그 id로 정규화(중복 방지). 예:
234	//   https://github.com/foo/bar.git → github-com-foo-bar
235	//   git@github.com:foo/bar.git     → github-com-foo-bar
236	//   /tmp/local-repo                → tmp-local-repo
237	function slugify(url) {
238	  let s = String(url).trim();
239	  s = s.replace(/^https?:\/\//i, '').replace(/^ssh:\/\//i, '');
240	  s = s.replace(/^git@/i, '').replace(/:/g, '/'); // scp 형식 host:owner → host/owner
241	  s = s.replace(/\.git$/i, '');
242	  s = s.replace(/[^a-zA-Z0-9]+/g, '-').replace(/^-+|-+$/g, '').toLowerCase();
243	  return s || 'reg';
244	}
245	
246	// URL에서 owner/repo 형태 추정(source_ref 표기용). 못 구하면 슬러그 끝 2토막.
247	function ownerRepoOf(url) {
248	  let s = String(url).trim().replace(/\.git$/i, '');
249	  s = s.replace(/^https?:\/\/[^/]+\//i, ''); // https://host/ 제거
250	  s = s.replace(/^git@[^:]+:/i, ''); // git@host: 제거
251	  s = s.replace(/^ssh:\/\/[^/]+\//i, '');
252	  const parts = s.split('/').filter(Boolean);
253	  if (parts.length >= 2) return parts.slice(-2).join('/');
254	  return parts.join('/') || slugify(url);
255	}
