285	// ── 퍼블리셔 그룹핑(SKC1) ────────────────────────────────────────────
286	// 평탄화 기본 repos + 사용자 추가분 + 캐시(실제 항목 수)를 퍼블리셔 카드로 묶는다.
287	//   [{ name, slug, official, repoCount, totalSkillsCurated, actualSkillCount,
288	//      refreshedRepoCount, repos:[{id,name,url,curated,actual}] }]
289	//  - actualSkillCount: 캐시에 하나라도 있으면 Σ 실제 항목수, 없으면 null.
290	//  - 사용자 추가분은 {name:'사용자', slug:'user', official:false} 그룹으로.
291	function publishersList() {
292	  const entries = list(); // 평면(기본 + 사용자) — publisher/publisherSlug/branch/skillCountCurated 포함
293	
294	  // repo id → 실제(캐시) 항목 수. 캐시 파일이 있으면 해당 repo는 "refreshed".
295	  const actualByRepo = new Map();
296	  for (const it of cachedItems()) {
297	    const rid = it.registry_id;
298	    if (!rid) continue;
299	    actualByRepo.set(rid, (actualByRepo.get(rid) || 0) + 1);
300	  }
301	  // 캐시 파일 존재 여부(0개짜리 repo도 refreshed로 카운트)로 refreshedRepoCount 산출.
302	  const refreshedRepoIds = new Set();
303	  try {
304	    const dir = paths.registryCacheDir();
305	    if (fs.existsSync(dir)) {
306	      for (const f of fs.readdirSync(dir)) {
307	        const m = /^registry-(.*)\.json$/.exec(f);
308	        if (m) refreshedRepoIds.add(m[1]);
309	      }
310	    }
311	  } catch {
312	    /* 캐시 디렉토리 없음 → refreshed 0 */
313	  }
314	
315	  const groups = new Map(); // slug → 카드
316	  function ensureGroup(slug, name, official) {
317	    if (!groups.has(slug)) {
318	      groups.set(slug, {
319	        name,
320	        slug,
321	        official,
322	        repoCount: 0,
323	        totalSkillsCurated: 0,
324	        actualSkillCount: null,
325	        refreshedRepoCount: 0,
326	        repos: [],
327	        _totalSkillsOverride: null,
328	      });
329	    }
330	    return groups.get(slug);
331	  }
332	
333	  // 퍼블리셔의 totalSkills(pub.totalSkills) 우선값을 별도로 뽑아 둔다.
334	  const pubTotals = new Map(); // slug → totalSkills
335	  const defaults = loadDefaultsRaw();
336	  for (const pub of defaults) pubTotals.set(pub.slug, pub.totalSkills);
337	
338	  for (const r of entries) {
339	    const slug = r.official ? r.publisherSlug || 'official' : 'user';
340	    const name = r.official ? r.publisher || slug : '사용자';
341	    const g = ensureGroup(slug, name, !!r.official);
342	    g.repoCount += 1;
343	    const curated = typeof r.skillCountCurated === 'number' ? r.skillCountCurated : null;
344	    if (curated != null) g.totalSkillsCurated += curated;
345	    const actual = actualByRepo.has(r.id) ? actualByRepo.get(r.id) : refreshedRepoIds.has(r.id) ? 0 : null;
346	    if (actual != null) {
347	      g.actualSkillCount = (g.actualSkillCount || 0) + actual;
348	    }
349	    if (refreshedRepoIds.has(r.id)) g.refreshedRepoCount += 1;
350	    g.repos.push({ id: r.id, name: r.name, url: r.url, curated, actual });
351	  }
352	
353	  // totalSkillsCurated = pub.totalSkills(있으면) 우선, 없으면 Σ skillCountCurated.
354	  const out = [];
355	  for (const g of groups.values()) {
356	    const pubTotal = pubTotals.get(g.slug);
357	    if (typeof pubTotal === 'number') g.totalSkillsCurated = pubTotal;
358	    delete g._totalSkillsOverride;
359	    out.push(g);
360	  }
361	  return out;
362	}
