430	// ── git 실행(비셸) ──────────────────────────────────────────────────
431	function runGit(args, { cwd } = {}) {
432	  return new Promise((resolve, reject) => {
433	    execFile('git', args, { cwd, timeout: GIT_TIMEOUT_MS, maxBuffer: 8 * 1024 * 1024 }, (err, stdout, stderr) => {
434	      if (err) {
435	        // 출력에 토큰류가 섞일 여지 없음(공개 repo·토큰 미사용). 메시지만 전달.
436	        const msg = (stderr || err.message || '').toString().trim();
437	        return reject(new Error('git ' + args[0] + ' 실패: ' + msg));
438	      }
439	      resolve({ stdout: stdout.toString(), stderr: stderr.toString() });
440	    });
441	  });
442	}
