461	// ── SKILL.md 탐색(레이아웃 3종 — skills-manage 개념) ─────────────────
462	//  1) 루트: <clone>/SKILL.md
463	//  2) <dir>/SKILL.md  (1단계 하위 폴더 각각)
464	//  3) skills/**/SKILL.md (skills 디렉토리 아래 재귀)
465	// 반환: [{ skillMdPath, dirName }]  (dirName = 스킬 이름 추정 fallback)
466	function findSkillFiles(root) {
467	  const found = [];
468	  const seen = new Set();
469	  function push(p, dirName) {
470	    const abs = path.resolve(p);
471	    if (seen.has(abs)) return;
472	    seen.add(abs);
473	    found.push({ skillMdPath: abs, dirName });
474	  }
475	
476	  // 1) 루트
477	  const rootSkill = path.join(root, 'SKILL.md');
478	  if (fs.existsSync(rootSkill)) push(rootSkill, path.basename(root));
479	
480	  // 2) 1단계 하위 폴더의 SKILL.md
481	  let topEntries = [];
482	  try {
483	    topEntries = fs.readdirSync(root, { withFileTypes: true });
484	  } catch {
485	    topEntries = [];
486	  }
487	  for (const e of topEntries) {
488	    if (!e.isDirectory() || e.name === '.git') continue;
489	    const p = path.join(root, e.name, 'SKILL.md');
490	    if (fs.existsSync(p)) push(p, e.name);
491	  }
492	
493	  // 3) skills/**/SKILL.md (재귀)
494	  const skillsRoot = path.join(root, 'skills');
495	  if (fs.existsSync(skillsRoot)) {
496	    walkForSkillMd(skillsRoot, push, 0);
497	  }
498	  return found;
499	}
500	
501	function walkForSkillMd(dir, push, depth) {
502	  if (depth > 6) return; // 방어적 깊이 제한
503	  let entries = [];
504	  try {
505	    entries = fs.readdirSync(dir, { withFileTypes: true });
506	  } catch {
507	    return;
508	  }
509	  for (const e of entries) {
510	    if (e.name === '.git') continue;
511	    const full = path.join(dir, e.name);
512	    if (e.isDirectory()) {
513	      walkForSkillMd(full, push, depth + 1);
514	    } else if (e.isFile() && e.name === 'SKILL.md') {
515	      push(full, path.basename(dir));
516	    }
517	  }
518	}
