520	// frontmatter에서 name/description/tags 추출(gray-matter). 실패해도 dirName fallback.
521	function parseSkillMd(skillMdPath, dirName) {
522	  let raw = '';
523	  try {
524	    raw = fs.readFileSync(skillMdPath, 'utf8');
525	  } catch {
526	    raw = '';
527	  }
528	  let data = {};
529	  try {
530	    data = matter(raw).data || {};
531	  } catch {
532	    data = {};
533	  }
534	  const name = (data.name && String(data.name).trim()) || dirName;
535	  const description = data.description ? String(data.description).trim() : '';
536	  let tags = [];
537	  if (Array.isArray(data.tags)) tags = data.tags.map((t) => String(t).trim()).filter(Boolean);
538	  else if (typeof data.tags === 'string') tags = data.tags.split(',').map((t) => t.trim()).filter(Boolean);
539	  // category는 문자열/배열 모두 허용(자동 카테고리화 입력).
540	  let category = [];
541	  if (Array.isArray(data.category)) category = data.category.map((t) => String(t).trim()).filter(Boolean);
542	  else if (typeof data.category === 'string') category = data.category.split(',').map((t) => t.trim()).filter(Boolean);
543	  return { name, description, tags, category, body: raw };
544	}
