546	// ── refresh: clone → 파싱 → 캐시 저장 → registries.json 갱신 ──────────
547	async function refresh(id) {
548	  const registry = findRegistry(id);
549	  if (!registry) throw new Error('등록되지 않은 레지스트리입니다: ' + id);
550	  const url = registry.url;
551	
552	  // ① 캐시 디렉토리에 clone(이미 있으면 삭제 후 재clone — 단순하게).
553	  //    branch 필드가 있으면 --branch로 지정(하드코딩 main 금지). 없으면 기본 브랜치.
554	  const dir = cloneDir(id);
555	  fs.mkdirSync(paths.registryCacheDir(), { recursive: true });
556	  rmrf(dir);
557	  const cloneArgs = ['clone', '--depth', '1'];
558	  if (registry.branch) cloneArgs.push('--branch', String(registry.branch));
559	  cloneArgs.push(url, dir);
560	  await runGit(cloneArgs);
561	
562	  // 커밋 해시(revision) 확보.
563	  let revision = null;
564	  try {
565	    const r = await runGit(['rev-parse', 'HEAD'], { cwd: dir });
566	    revision = r.stdout.trim() || null;
567	  } catch {
568	    revision = null;
569	  }
570	
571	  // ③ SKILL.md 탐색 + ④ frontmatter 파싱 + 자동 카테고리화.
572	  const sourceRef = ownerRepoOf(url);
573	  const repoFullName = registry.name || sourceRef; // owner/repo (v2 repo.name)
574	  const publisher = registry.publisher || null;
575	  const publisherSlug = registry.publisherSlug || null;
576	  const recIndex = loadRecommendedIndex();
577	  const skillFiles = findSkillFiles(dir);
578	  const items = [];
579	  for (const sf of skillFiles) {
580	    const parsed = parseSkillMd(sf.skillMdPath, sf.dirName);
581	    // ⑤ 자동 태그: recommended(repo+name) 우선 → frontmatter → 휴리스틱.
582	    let tags;
583	    const recKey = String(repoFullName).toLowerCase() + ' ' + String(parsed.name).toLowerCase();
584	    if (recIndex.has(recKey)) {
585	      // recommended-skills.json의 태그를 유효 key로만 채택(최우선).
586	      const valid = validTagKeys();
587	      tags = recIndex.get(recKey).map((t) => String(t).toLowerCase()).filter((t) => valid.has(t));
588	    } else {
589	      tags = categorize({
590	        name: parsed.name,
591	        description: parsed.description,
592	        frontmatterTags: parsed.tags,
593	        frontmatterCategory: parsed.category,
594	      });
595	    }
596	    // ⑥ 스키마 = 기존 catalog.json 항목 + registry 출처 메타 + 퍼블리셔/소스repo.
597	    items.push({
598	      id: 'reg-' + id + '-' + parsed.name,
599	      kind: 'skill',
600	      name: parsed.name,
601	      tags,
602	      description: parsed.description,
603	      official: true,
604	      source: 'registry',
605	      source_type: 'registry',
606	      source_ref: sourceRef,
607	      source_revision: revision,
608	      registry_id: id,
609	      publisher,
610	      publisherSlug,
611	      sourceRepo: repoFullName,
612	      body: parsed.body,
613	    });
614	  }
615	
616	  // ⑥ .git 폴더 제거(용량·시크릿 위생) — 캐시엔 파싱된 결과만 남긴다.
617	  rmrf(dir);
618	
619	  // 캐시 파일 저장.
620	  const cacheFile = registryItemsFile(id);
621	  fs.mkdirSync(path.dirname(cacheFile), { recursive: true });
622	  fs.writeFileSync(
623	    cacheFile,
624	    JSON.stringify({ version: 1, registry_id: id, source_ref: sourceRef, revision, generated_at: new Date().toISOString(), items }, null, 2) + '\n',
625	    'utf8'
626	  );
627	
628	  // revision·last_refreshed 갱신.
629	  //  - 사용자 레지스트리: registries.json의 항목에 직접 기록.
630	  //  - 기본(official) 레지스트리: registries.json의 defaultsOverlay[id]에 기록
631	  //    (default-registries.json 번들 원본은 절대 쓰지 않는다 — 정적 유지).
632	  const now = new Date().toISOString();
633	  const reg = load();
634	  const target = reg.registries.find((r) => r.id === id);
635	  if (target) {
636	    target.revision = revision;
637	    target.last_refreshed = now;
638	    save(reg);
639	  } else {
640	    reg.defaultsOverlay = reg.defaultsOverlay || {};
641	    reg.defaultsOverlay[id] = { revision, last_refreshed: now };
642	    save(reg);
643	  }
644	
645	  return { id, url, revision, source_ref: sourceRef, count: items.length, cacheFile };
646	}
