648	// 캐시된 레지스트리 항목 전부 로드(store.js 병합용). 없으면 빈 배열.
649	function cachedItems() {
650	  const dir = paths.registryCacheDir();
651	  if (!fs.existsSync(dir)) return [];
652	  let files = [];
653	  try {
654	    files = fs.readdirSync(dir).filter((f) => /^registry-.*\.json$/.test(f));
655	  } catch {
656	    return [];
657	  }
658	  const out = [];
659	  for (const f of files) {
660	    try {
661	      const data = JSON.parse(fs.readFileSync(path.join(dir, f), 'utf8'));
662	      if (Array.isArray(data.items)) out.push(...data.items);
663	    } catch {
664	      /* 깨진 캐시 파일은 건너뜀 */
665	    }
666	  }
667	  return out;
668	}
