670	// ── checkUpdates: git ls-remote HEAD 로 저장 revision과 비교 ──────────
671	// 통신 실패는 error로 기록만 하고 throw로 전체를 중단하지 않는다.
672	async function checkUpdates() {
673	  const registries = list();
674	  const results = [];
675	  for (const r of registries) {
676	    try {
677	      const out = await runGit(['ls-remote', r.url, 'HEAD']);
678	      const remoteRev = (out.stdout.trim().split(/\s+/)[0] || '') || null;
679	      const update_available = !!r.revision && !!remoteRev && r.revision !== remoteRev;
680	      results.push({ id: r.id, remote_revision: remoteRev, local_revision: r.revision || null, update_available });
681	    } catch (e) {
682	      results.push({ id: r.id, error: e.message, update_available: false });
683	    }
684	  }
685	  return results;
686	}
