66	function cmdPull(args) {
67	  const from = args.from;
68	  if (!from) {
69	    console.error('사용법: aad pull --from <claude|codex|gemini> [--pi-ack <mask|exclude|proceed>]');
70	    process.exit(1);
71	  }
72	  try {
73	    const r = core.pull({ from, piAck: args['pi-ack'] });
74	    if (!r.imported) {
75	      console.log('PI 게이트: 사용자가 제외를 선택 → 가져오지 않았습니다.');
76	      return;
77	    }
78	    if (r.piHandled === 'mask') console.log('PI 게이트: 마스킹 후 가져옵니다.');
79	    if (r.piHandled === 'proceed') console.log('PI 게이트: 그대로 진행을 선택했습니다.');
80	    console.log(`✓ canonical에 가져왔습니다: ${core.CANON_ID} (출처 ${r.meta.source_tool})`);
81	  } catch (e) {
82	    if (e instanceof core.PiGateError) {
83	      console.error('⚠ 민감 정보가 감지되었습니다. canonical 반영 전에 확인이 필요합니다.');
84	      console.error('  감지: ' + e.detected.join(', '));
85	      console.error('  해당 줄(마스킹):');
86	      for (const line of e.maskedLines) console.error('    ' + line);
87	      console.error('');
88	      console.error('  다시 실행하며 처리 방식을 지정하세요:');
89	      console.error('    --pi-ack mask | exclude | proceed');
90	      process.exit(2);
91	    }
92	    console.error(e.message);
93	    process.exit(1);
94	  }
95	}
