2	// 프로젝트(저장소) 레지스트리 + "최초 1회" 디스크 스캔 (T1).
3	//
4	// 설계 원칙(사용자 결정): 디스크 스캔은 최초 1회(또는 사용자가 명시적으로 재스캔을
5	// 눌렀을 때)만 실행한다. 평소에는 projects.json에 저장된 목록(list)만 쓴다.
6	// 자동/백그라운드 스캔은 없다.
7	//
8	// ★ 보안 가드:
9	//  - scan()은 디렉토리 "이름/존재"만 본다. 어떤 파일의 내용도 읽지 않는다
10	//    (readdir/stat 계열만 사용 — fs.readFile 금지).
11	//  - 심볼릭 링크는 따라가지 않는다(무한 루프 방지).
12	//  - 도구 홈 자체(~/.claude·~/.codex·~/.gemini·~/.agents)는 프로젝트가 아니므로 후보 제외.
13	//  - EXCLUDE_DIRS와 숨김 디렉토리('.'로 시작)에는 하위 진입하지 않는다
14	//    (마커 존재 확인용 stat은 허용).
15	
16	const fs = require('fs');
17	const os = require('os');
18	const path = require('path');
19	const paths = require('./paths');
20	
21	// 프로젝트로 인정하는 마커 — 존재만 확인 (0번 검증 문서의 도구별 프로젝트 위치 기준)
22	const MARKERS = ['.claude', 'CLAUDE.md', 'AGENTS.md', '.agents', 'GEMINI.md', '.gemini', '.codex'];
23	
24	// 하위 진입 금지 디렉토리 (성능·안전 — 진입만 금지, 마커 stat은 별개)
25	const EXCLUDE_DIRS = [
26	  'node_modules', '.git', 'Library', '.Trash', '.cache', '.npm', '.nvm',
27	  '.vscode', '.cursor', 'Applications', 'Music', 'Movies', 'Pictures',
28	];
29	
30	// 도구 홈 절대 경로 집합 — 스캔 후보에서 제외할 대상
31	function toolHomeSet() {
32	  const h = os.homedir();
33	  return new Set([
34	    path.join(h, '.claude'),
35	    path.join(h, '.codex'),
36	    path.join(h, '.gemini'),
37	    path.join(h, '.agents'),
38	  ]);
39	}
40	
41	// 폴더에 존재하는 마커 목록. lstat으로 "존재"만 확인한다(내용 안 읽음).
42	function markersOf(dir) {
43	  const found = [];
44	  for (const m of MARKERS) {
45	    try {
46	      fs.lstatSync(path.join(dir, m));
47	      found.push(m);
48	    } catch {
49	      // 없음 — 통과
50	    }
51	  }
52	  return found;
53	}
54	
55	// rootDir부터 트리를 내려가며 MARKERS 중 하나라도 있는 폴더를 후보로 수집한다.
56	//  - 후보 발견 시 그 폴더 하위로는 더 내려가지 않는다(중첩 프로젝트는 1차 범위 밖).
57	//  - 홈 디렉토리 자체는 후보로 삼지 않는다(홈의 .claude 등은 프로젝트 마커가 아니라
58	//    글로벌 도구 홈이므로) — 하위 탐색은 계속한다.
59	//  - 반환: [{ root, markers: [...] }]
60	function scan(rootDir, { maxDepth = 4 } = {}) {
61	  const found = [];
62	  const toolHomes = toolHomeSet();
63	  const home = os.homedir();
64	
65	  function walk(dir, depth) {
66	    if (toolHomes.has(dir)) return; // 도구 홈 자체는 프로젝트가 아님
67	    let st;
68	    try {
69	      st = fs.lstatSync(dir);
70	    } catch {
71	      return; // 접근 불가/없음 — 조용히 건너뜀
72	    }
73	    if (st.isSymbolicLink() || !st.isDirectory()) return;
74	
75	    if (dir !== home) {
76	      const markers = markersOf(dir);
77	      if (markers.length > 0) {
78	        found.push({ root: dir, markers });
79	        return; // 후보 발견 — 하위 진입 중단
80	      }
81	    }
82	
83	    if (depth >= maxDepth) return;
84	    let entries;
85	    try {
86	      entries = fs.readdirSync(dir, { withFileTypes: true });
87	    } catch {
88	      return; // 권한 없음 등 — 조용히 건너뜀
89	    }
90	    for (const e of entries) {
91	      if (!e.isDirectory() || e.isSymbolicLink()) continue; // 심볼릭 링크 안 따라감
92	      if (e.name.startsWith('.') || EXCLUDE_DIRS.includes(e.name)) continue; // 진입 금지
93	      walk(path.join(dir, e.name), depth + 1);
94	    }
95	  }
96	
97	  walk(path.resolve(rootDir), 0);
98	  return found;
99	}
100	
101	// projects.json 읽기. 없거나 깨졌으면 기본값 {version:1, projects:[]}.
102	function load() {
103	  const file = paths.projectsFile();
104	  if (!fs.existsSync(file)) return { version: 1, projects: [] };
105	  try {
106	    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
107	    if (!data || !Array.isArray(data.projects)) return { version: 1, projects: [] };
108	    return { version: data.version || 1, projects: data.projects };
109	  } catch {
110	    return { version: 1, projects: [] };
111	  }
112	}
113	
114	// projects.json 쓰기 (paths.projectsFile 위치 — 모드별 canonical에 자동 격리).
115	// 레지스트리 객체({version, projects}) 또는 프로젝트 배열 둘 다 받는다.
116	function save(reg) {
117	  const data = Array.isArray(reg) ? { version: 1, projects: reg } : reg;
118	  const file = paths.projectsFile();
119	  fs.mkdirSync(path.dirname(file), { recursive: true });
120	  fs.writeFileSync(file, JSON.stringify(data, null, 2) + '\n', 'utf8');
121	  return file;
122	}
123	
124	// 수동 등록: 존재하는 디렉토리 + 마커 1개 이상 확인, 중복(root)이면 무시.
125	function add(root) {
126	  const abs = path.resolve(root);
127	  let st;
128	  try {
129	    st = fs.statSync(abs);
130	  } catch {
131	    throw new Error('경로가 존재하지 않습니다: ' + abs);
132	  }
133	  if (!st.isDirectory()) throw new Error('디렉토리가 아닙니다: ' + abs);
134	  const markers = markersOf(abs);
135	  if (markers.length === 0) {
136	    throw new Error('프로젝트 마커(' + MARKERS.join('/') + ')가 없습니다: ' + abs);
137	  }
138	  const reg = load();
139	  if (reg.projects.some((p) => p.root === abs)) {
140	    return { added: false, reason: 'duplicate', root: abs };
141	  }
142	  const entry = { root: abs, markers, added_at: new Date().toISOString(), source: 'manual' };
143	  reg.projects.push(entry);
144	  save(reg);
145	  return { added: true, project: entry };
146	}
147	
148	// 등록 해제 (root 절대경로 기준).
149	function remove(root) {
150	  const abs = path.resolve(root);
151	  const reg = load();
152	  const before = reg.projects.length;
153	  reg.projects = reg.projects.filter((p) => p.root !== abs);
154	  if (reg.projects.length === before) return { removed: false, root: abs };
155	  save(reg);
156	  return { removed: true, root: abs };
157	}
158	
159	// 등록된 프로젝트 배열.
160	function list() {
161	  return load().projects;
162	}
163	
164	// scan() 결과를 레지스트리에 병합. 이미 등록된 root는 건너뛴다(source:'scan').
165	function adoptScan(candidates) {
166	  const reg = load();
167	  const known = new Set(reg.projects.map((p) => p.root));
168	  const adopted = [];
169	  for (const c of candidates || []) {
170	    if (!c || !c.root || known.has(c.root)) continue;
171	    const entry = {
172	      root: c.root,
173	      markers: Array.isArray(c.markers) ? c.markers : [],
174	      added_at: new Date().toISOString(),
175	      source: 'scan',
176	    };
177	    reg.projects.push(entry);
178	    known.add(c.root);
179	    adopted.push(entry);
180	  }
181	  if (adopted.length > 0) save(reg);
182	  return { adopted: adopted.length, total: reg.projects.length };
183	}
184	
185	module.exports = { MARKERS, EXCLUDE_DIRS, scan, load, save, add, remove, list, adoptScan };
