// ── collectMissing: 시작 시 증분 수집 (F2-3) ─────────────────────────
// 등록된 레지스트리 중 "캐시가 없는 것만" clone(refresh)한다. 이미 캐시된 것은
// git ls-remote HEAD 해시가 캐시(저장 revision)와 다를 때만 재수집한다.
//  - 78개 전부 매번 clone 금지 — 캐시 존재 + 해시 동일이면 skip.
//  - concurrency 기본 2(최대 3). 레지스트리별 실패는 error로 기록하고 계속(전체 중단 금지).
//  - 진행 상태를 모듈 내부 상태로 유지하고 collectStatus()로 조회한다.
//  - 외부 통신은 "앱 실행=사용자 트리거"(D28)로 간주해 시작 훅에서만 kick한다(자동 폴링 아님).

// 모듈 내부 진행 상태 (collectStatus()로 조회).
let _collectState = { running: false, total: 0, done: 0, failed: 0, errors: [] };

function collectStatus() {
  // 방어적 복사(호출자가 errors 배열을 변형하지 못하게).
  return {
    running: _collectState.running,
    total: _collectState.total,
    done: _collectState.done,
    failed: _collectState.failed,
    errors: _collectState.errors.map((e) => ({ name: e.name, message: e.message })),
  };
}

// 캐시 파일의 저장 revision(있으면). 없거나 깨지면 null.
function cachedRevision(id) {
  try {
    const file = registryItemsFile(id);
    if (!fs.existsSync(file)) return null;
    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
    return data && data.revision ? String(data.revision) : null;
  } catch {
    return null;
  }
}

// 한 레지스트리가 "재수집이 필요한지" 판정.
//  - 캐시 파일 없음 → 무조건 필요(미수집).
//  - 캐시 있음 → ls-remote HEAD 와 저장 revision 비교. 다르면 필요, 같으면 skip.
//    (ls-remote 실패 시엔 보수적으로 skip — 이미 캐시가 있으므로 기존 것 유지.)
async function needsCollect(reg) {
  const file = registryItemsFile(reg.id);
  if (!fs.existsSync(file)) return true; // 미수집 → clone
  const localRev = cachedRevision(reg.id);
  if (!localRev) return true; // 캐시는 있으나 revision 미상 → 재수집
  const out = await runGit(['ls-remote', reg.url, 'HEAD']);
  const remoteRev = (out.stdout.trim().split(/\s+/)[0] || '') || null;
  if (!remoteRev) return false; // 원격 해시 못 구함 → 기존 캐시 유지(skip)
  return remoteRev !== localRev; // 변경됐을 때만 재수집
}

// 증분 수집 실행. concurrency 워커로 병렬 처리(기본 2, 최대 3).
// 이미 실행 중이면 현재 상태만 돌려준다(중복 kick 방지).
async function collectMissing({ concurrency = 2 } = {}) {
  if (_collectState.running) return collectStatus();
  const conc = Math.max(1, Math.min(3, Number(concurrency) || 2));

  const registries = list();
  _collectState = { running: true, total: registries.length, done: 0, failed: 0, errors: [] };

  let cursor = 0;
  async function worker() {
    for (;;) {
      const idx = cursor++;
      if (idx >= registries.length) return;
      const reg = registries[idx];
      try {
        let needed;
        try {
          needed = await needsCollect(reg);
        } catch (e) {
          // ls-remote 등 통신 실패: 이 레지스트리만 실패로 기록하고 계속.
          _collectState.failed += 1;
          _collectState.errors.push({ name: reg.name || reg.id, message: e.message });
          _collectState.done += 1;
          continue;
        }
        if (needed) {
          await refresh(reg.id); // clone→파싱→캐시(기존 파이프라인 재사용, .git 제거 포함)
        }
        _collectState.done += 1;
      } catch (e) {
        // refresh(clone) 실패: 이 레지스트리만 실패로 기록하고 계속.
        _collectState.failed += 1;
        _collectState.errors.push({ name: reg.name || reg.id, message: e.message });
        _collectState.done += 1;
      }
    }
  }

  const workers = [];
  for (let i = 0; i < conc; i++) workers.push(worker());
  try {
    await Promise.all(workers);
  } finally {
    _collectState.running = false;
  }
  return collectStatus();
}

// ── checkUpdates: git ls-remote HEAD 로 저장 revision과 비교 ──────────

// ================= 지시문 매트릭스 / 한 방 동기화 (UX v2 — F2) =================
// D27/UX v2: canonical은 순수 백업이라 지시문 비교 계산에 넣지 않는다(3파일만 비교).
// 해시·그룹·상태 로직은 syncMatrix(buildSkillRow)의 규칙을 그대로 재사용한다(contentHash + 그룹 번호).
// 읽기 실패는 throw하지 않고 해당 모델에 readError로 담아 우아하게 반환한다(D26).

// (1) instrMatrix — 전역 지시문 3파일 비교.
//  - 모델별 { exists, group(내용 해시 그룹 번호|null), readError? } 반환.
//  - 종합 상태(syncState):
//      synced : 셋 다 존재 + 같은 해시(그룹 1개)
//      drift  : 존재하는 것끼리 해시가 갈림(그룹 2개 이상)
//      partial: 일부만 존재(있는 것끼리는 동일)
//      none   : 하나도 없음
function instrMatrix() {
  // 내용 해시 → 그룹 번호(1부터). buildSkillRow와 동일한 idiom.
  const groupOf = new Map();
  let nextGroup = 0;
  const assign = (h) => {
    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
    return groupOf.get(h);
  };

  const discovered = scanner.discoverInstructions(); // {tool, path, exists, ...}[]
  const models = {};
  for (const tool of paths.TOOLS) {
    const item = discovered.find((i) => i.tool === tool);
    if (!item || !item.exists) {
      models[tool] = { exists: false, group: null };
      continue;
    }
    try {
      // readItemContent는 거부목록/PI 가드를 상속(지시문 본문 읽기는 사용자 트리거 화면 로드).
      const { text } = scanner.readItemContent({ path: item.path });
      models[tool] = { exists: true, group: assign(contentHash(text)) };
    } catch (e) {
      // 우아한 실패(D26): 이 모델만 readError, 나머지는 계속.
      models[tool] = { exists: false, group: null, readError: e.message };
    }
  }

  // 종합 상태 판정(지시문 전용 — none이 별도 상태라 syncStateOf와 규칙이 다름).
  const present = paths.TOOLS.map((t) => models[t]).filter((s) => s.exists && s.group != null);
  let syncState;
  if (present.length === 0) syncState = 'none';
  else if (groupOf.size > 1) syncState = 'drift';
  else syncState = present.length === paths.TOOLS.length ? 'synced' : 'partial';

  return {
    canonId: CANON_ID,
    models,
    groups: groupOf.size,
    syncState,
  };
}

// (2) instrSync — 기준 모델로 한 방 동기화.
//  - base = 'claude'|'codex'|'gemini'.
//  - apply:false(기본): 실제 쓰기 없이 모델별 diff 요약(변경 라인 수·생성될 파일 여부)만 반환.
//      · 쓰기 없음 검증을 위해 canonical에도 쓰지 않는다 — 기준 파일 본문을 직접 읽어
//        transformInstr.render + diff.lineDiff로 대상별 미리보기를 만든다(디스크 무변경).
//  - apply:true: 기존 pull({from:base}) → push({to,apply:true}) 파이프라인을 그대로 재사용
//      (자동 백업·synclog·PI 게이트·gitCommit 상속). 새 쓰기 경로는 만들지 않는다.
//      PI 게이트는 pull이 PiGateError를 던지며 여기서 잡지 않고 그대로 전파(서버 409).
function instrSync({ base, apply, piAck }) {
  if (!paths.TOOLS.includes(base)) {
    throw new Error("기준 모델(base)이 올바르지 않습니다: " + base + " ('claude'|'codex'|'gemini')");
  }
  const baseItem = scanner.discoverInstructions().find((i) => i.tool === base);
  if (!baseItem || !baseItem.exists) {
    throw new Error(`기준 모델(${base})의 지시문 파일이 없습니다: ${baseItem ? baseItem.path : base}`);
  }

  if (!apply) {
    // 미리보기: 디스크 무변경. 기준 파일 본문을 읽어 대상 모델별 diff 요약만 만든다.
    const { text: baseBody } = scanner.readItemContent({ path: baseItem.path });
    const targets = paths.TOOLS.filter((t) => t !== base).map((to) => {
      const rendered = transformInstr.render(baseBody, to); // 지시문은 본문 변환 없음(파일명만)
      const exists = fs.existsSync(rendered.targetPath);
      const deployed = exists ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
      const d = diff.lineDiff(deployed, rendered.body);
      const added = d.filter((x) => x.type === '+').length;
      const removed = d.filter((x) => x.type === '-').length;
      return {
        to,
        targetPath: rendered.targetPath,
        exists,
        willCreate: !exists,     // 대상 파일이 없으면 새로 생성됨
        hasChanges: diff.hasChanges(d),
        added,                   // 추가될 라인 수
        removed,                 // 사라질 라인 수
        changedLines: added + removed,
      };
    });
    return { applied: false, base, targets };
  }

  // 적용: 기존 파이프라인 재사용. pull(base→canonical) 후 나머지 모델로 push(apply:true).
  const pulled = pull({ from: base, piAck }); // PI 게이트 시 PiGateError 전파
  if (!pulled.imported) {
    // PI 게이트에서 사용자가 제외를 선택 → 기준을 canonical에 넣지 않아 동기화 중단.
    return { applied: true, base, pulled: { imported: false, reason: pulled.reason }, results: [] };
  }
  const results = [];
  for (const to of paths.TOOLS) {
    if (to === base) continue;
    try {
      const r = push({ to, apply: true }); // 자동 백업·synclog·gitCommit 상속
      results.push({ to, applied: true, targetPath: r.targetPath, backupPath: r.backupPath || null });
    } catch (e) {
      // 부분 실패: 중단하지 말고 모델별 결과로 기록.
      results.push({ to, applied: false, error: e.message });
    }
  }
  return {
    applied: true,
    base,
    pulled: { imported: true, source_tool: pulled.meta.source_tool, piHandled: pulled.piHandled },
    results,
  };
}

// ================= 백업 목록 / 복구 (UX-D1) =================

function registryCheckUpdates() {
  return registry.checkUpdates();
}
// F2-3: 시작 시 증분 수집(비차단 kick은 serve에서). 진행 상태 조회는 동기.
function registryCollectMissing({ concurrency } = {}) {
  return registry.collectMissing({ concurrency });
}
function registryCollectStatus() {
  return registry.collectStatus();
}

