// ---------------- 지시문 한 방 동기화 (UX v2 — F2) ----------------
// aad instr sync --base <claude|codex|gemini> [--apply] [--pi-ack ...]
// --apply 없으면 기준 모델로 맞출 때의 diff 요약(변경 라인 수·생성 여부)만 출력(디스크 무변경).
function cmdInstr(rest) {
  const sub = rest[0];
  const args = parseArgs(rest.slice(1));
  if (sub !== 'sync') {
    console.error('사용법: aad instr sync --base <claude|codex|gemini> [--apply] [--pi-ack <mask|exclude|proceed>]');
    process.exit(1);
  }
  const base = args.base;
  if (!base || base === true) {
    console.error('사용법: aad instr sync --base <claude|codex|gemini> [--apply] [--pi-ack <mask|exclude|proceed>]');
    process.exit(1);
  }
  try {
    const r = core.instrSync({ base, apply: !!args.apply, piAck: args['pi-ack'] });
    if (!args.apply) {
      console.log(`지시문 동기화 미리보기 (기준: ${r.base}) — 디스크 무변경`);
      console.log('대상      존재   변경(+/-)     동작');
      for (const t of r.targets) {
        const chg = t.hasChanges ? `+${t.added}/-${t.removed}` : '변경 없음';
        const action = t.willCreate ? '신규 생성' : t.hasChanges ? '덮어쓰기' : '(동일)';
        console.log(t.to.padEnd(9) + (t.exists ? '✓' : '✗').padEnd(6) + chg.padEnd(13) + action);
      }
      console.log('\n실제 적용하려면 --apply 를 붙이세요 (기준→canonical pull 후 나머지 모델 push, 백업 자동).');
      return;
    }
    // 적용 결과
    if (r.pulled && r.pulled.imported === false) {
      console.log(`PI 게이트: 제외 선택 → 기준(${r.base})을 가져오지 않아 동기화 중단.`);
      return;
    }
    console.log(`✓ pull: ${r.base} → canonical` + (r.pulled.piHandled ? ` (PI:${r.pulled.piHandled})` : ''));
    console.log('push 결과:');
    for (const x of r.results) {
      if (x.applied) {
        console.log(`  ${x.to}: 적용 → ${x.targetPath}` + (x.backupPath ? `  (백업 ${x.backupPath})` : '  (신규라 백업 없음)'));
      } else {
        console.log(`  ${x.to}: ✗ 오류 — ${x.error}`);
      }
    }
  } catch (e) {
    if (e instanceof core.PiGateError) {
      console.error('⚠ 민감 정보 감지: ' + e.detected.join(', '));
      for (const l of e.maskedLines) console.error('    ' + l);
      console.error('  --pi-ack mask | exclude | proceed 로 다시 실행하세요.');
      process.exit(2);
    }
    console.error(e.message);
    process.exit(1);
  }
}

