'use strict';
// 격리 검증: instrMatrix 4상태 + instrSync apply:false(무변경)/apply:true(격리홈+백업).
// 실제 홈/canonical/backups에 절대 쓰지 않는다 — AAD_FIXTURES/AAD_CANONICAL/AAD_BACKUPS 오버라이드 + dummy 모드.

const fs = require('fs');
const path = require('path');
const os = require('os');

const SCRATCH = process.env.SCRATCH || path.join(os.tmpdir(), 'aad-instr-test');
const PROJ = '/Users/won-yechan/miru_github/agent-dashboard';

// 격리 환경: 가짜 홈(fixtures), 격리 canonical/backups. dummy 모드 유지(AAD_ALLOW_REAL 미설정).
function freshEnv(name) {
  const base = path.join(SCRATCH, name);
  fs.rmSync(base, { recursive: true, force: true });
  const fixtures = path.join(base, 'fixtures');
  fs.mkdirSync(path.join(fixtures, 'claude'), { recursive: true });
  fs.mkdirSync(path.join(fixtures, 'codex'), { recursive: true });
  fs.mkdirSync(path.join(fixtures, 'gemini'), { recursive: true });
  process.env.AAD_FIXTURES = fixtures;
  process.env.AAD_CANONICAL = path.join(base, 'canonical');
  process.env.AAD_BACKUPS = path.join(base, 'backups');
  delete process.env.AAD_MODE;
  delete process.env.AAD_ALLOW_REAL;
  return { base, fixtures };
}

function writeInstr(fixtures, tool, body) {
  const fn = { claude: 'CLAUDE.md', codex: 'AGENTS.md', gemini: 'GEMINI.md' }[tool];
  fs.writeFileSync(path.join(fixtures, tool, fn), body);
}

// core를 매 케이스마다 새로 require(모듈 캐시 초기화 — mode.js가 시작 시점 env를 읽으므로).
function loadCore() {
  for (const k of Object.keys(require.cache)) {
    if (k.includes(path.join(PROJ, 'cli')) || k.includes(path.join(PROJ, 'server'))) delete require.cache[k];
  }
  return require(path.join(PROJ, 'cli', 'core.js'));
}

let pass = 0, fail = 0;
function check(label, cond, extra) {
  if (cond) { pass++; console.log('  ✓ ' + label); }
  else { fail++; console.log('  ✗ ' + label + (extra ? '  → ' + JSON.stringify(extra) : '')); }
}

// ── 1) instrMatrix — 4 상태 ──
console.log('[1] instrMatrix 4상태 판정');

// synced: 셋 다 존재 + 동일 내용
{
  const { fixtures } = freshEnv('synced');
  writeInstr(fixtures, 'claude', 'SAME BODY\n');
  writeInstr(fixtures, 'codex', 'SAME BODY\n');
  writeInstr(fixtures, 'gemini', 'SAME BODY\n');
  const core = loadCore();
  const m = core.instrMatrix();
  check('synced 상태', m.syncState === 'synced', m.syncState);
  check('synced: 그룹 1개', m.groups === 1, m.groups);
  check('synced: 세 모델 같은 group', m.models.claude.group === m.models.codex.group && m.models.codex.group === m.models.gemini.group, m.models);
}

// drift: 존재하는 것끼리 내용 다름
{
  const { fixtures } = freshEnv('drift');
  writeInstr(fixtures, 'claude', 'AAA\n');
  writeInstr(fixtures, 'codex', 'BBB\n');
  writeInstr(fixtures, 'gemini', 'AAA\n');
  const core = loadCore();
  const m = core.instrMatrix();
  check('drift 상태', m.syncState === 'drift', m.syncState);
  check('drift: 그룹 2개', m.groups === 2, m.groups);
  check('drift: claude==gemini group', m.models.claude.group === m.models.gemini.group && m.models.codex.group !== m.models.claude.group, m.models);
}

// partial: 일부만 존재(있는 것끼리 동일)
{
  const { fixtures } = freshEnv('partial');
  writeInstr(fixtures, 'claude', 'ONLY TWO\n');
  writeInstr(fixtures, 'codex', 'ONLY TWO\n');
  // gemini 없음
  const core = loadCore();
  const m = core.instrMatrix();
  check('partial 상태', m.syncState === 'partial', m.syncState);
  check('partial: gemini exists=false', m.models.gemini.exists === false, m.models.gemini);
  check('partial: 그룹 1개', m.groups === 1, m.groups);
}

// none: 하나도 없음
{
  freshEnv('none');
  const core = loadCore();
  const m = core.instrMatrix();
  check('none 상태', m.syncState === 'none', m.syncState);
  check('none: 그룹 0', m.groups === 0, m.groups);
  check('none: 세 모델 모두 exists=false', !m.models.claude.exists && !m.models.codex.exists && !m.models.gemini.exists, m.models);
}

// ── 2) instrSync apply:false — 디스크 무변경 + diff 요약 ──
console.log('\n[2] instrSync apply:false (미리보기, 디스크 무변경)');
{
  const { base, fixtures } = freshEnv('preview');
  writeInstr(fixtures, 'claude', 'BASE LINE 1\nBASE LINE 2\n');
  writeInstr(fixtures, 'codex', 'OLD CODEX\n'); // 존재하지만 다름
  // gemini 없음 → willCreate
  const core = loadCore();

  // 스냅샷: 파일 내용 + canonical 존재
  const before = {
    claude: fs.readFileSync(path.join(fixtures, 'claude', 'CLAUDE.md'), 'utf8'),
    codex: fs.readFileSync(path.join(fixtures, 'codex', 'AGENTS.md'), 'utf8'),
    geminiExists: fs.existsSync(path.join(fixtures, 'gemini', 'GEMINI.md')),
    canonicalExists: fs.existsSync(path.join(base, 'canonical')),
  };

  const r = core.instrSync({ base: 'claude', apply: false });
  check('applied=false', r.applied === false, r.applied);
  check('base=claude', r.base === 'claude', r.base);
  check('targets 2개(codex,gemini)', r.targets.length === 2, r.targets.map(t => t.to));
  const codexT = r.targets.find(t => t.to === 'codex');
  const gemiT = r.targets.find(t => t.to === 'gemini');
  check('codex: hasChanges, exists', codexT.hasChanges === true && codexT.exists === true && codexT.willCreate === false, codexT);
  check('codex: changedLines > 0', codexT.changedLines > 0, codexT.changedLines);
  check('gemini: willCreate', gemiT.willCreate === true && gemiT.exists === false, gemiT);

  // 무변경 검증
  const after = {
    claude: fs.readFileSync(path.join(fixtures, 'claude', 'CLAUDE.md'), 'utf8'),
    codex: fs.readFileSync(path.join(fixtures, 'codex', 'AGENTS.md'), 'utf8'),
    geminiExists: fs.existsSync(path.join(fixtures, 'gemini', 'GEMINI.md')),
    canonicalExists: fs.existsSync(path.join(base, 'canonical')),
  };
  check('미리보기 후 claude 파일 무변경', before.claude === after.claude);
  check('미리보기 후 codex 파일 무변경', before.codex === after.codex);
  check('미리보기 후 gemini 여전히 없음', after.geminiExists === false);
  check('미리보기 후 canonical 생성 안 됨', after.canonicalExists === false, after.canonicalExists);
}

// ── 3) instrSync apply:true — 격리홈에만 쓰기 + 백업 ──
console.log('\n[3] instrSync apply:true (격리홈 쓰기 + 백업)');
{
  const { base, fixtures } = freshEnv('apply');
  writeInstr(fixtures, 'claude', 'CANONICAL SOURCE\nline2\n');
  writeInstr(fixtures, 'codex', 'OLD CODEX CONTENT\n'); // 기존 파일 → 덮어쓰기 시 백업 생겨야 함
  // gemini 없음 → 신규 생성(백업 없음)
  const core = loadCore();
  const r = core.instrSync({ base: 'claude', apply: true });
  check('applied=true', r.applied === true, r.applied);
  check('pulled.imported', r.pulled.imported === true, r.pulled);
  check('results 2개', r.results.length === 2, r.results.length);

  // 격리홈에 실제로 써졌는지
  const codexBody = fs.readFileSync(path.join(fixtures, 'codex', 'AGENTS.md'), 'utf8');
  const gemiBody = fs.readFileSync(path.join(fixtures, 'gemini', 'GEMINI.md'), 'utf8');
  check('codex에 기준 내용 써짐', codexBody === 'CANONICAL SOURCE\nline2\n', codexBody);
  check('gemini에 기준 내용 써짐(신규)', gemiBody === 'CANONICAL SOURCE\nline2\n', gemiBody);

  // 백업: codex는 기존 파일이 있었으니 백업 경로가 있어야 하고, 백업 파일에 옛 내용이 있어야 함
  const codexR = r.results.find(x => x.to === 'codex');
  const gemiR = r.results.find(x => x.to === 'gemini');
  check('codex 백업 경로 존재', !!codexR.backupPath, codexR);
  check('codex 백업이 격리 backups 폴더 안', codexR.backupPath && codexR.backupPath.startsWith(path.join(base, 'backups')), codexR.backupPath);
  if (codexR.backupPath && fs.existsSync(codexR.backupPath)) {
    check('codex 백업 내용 = 옛 codex', fs.readFileSync(codexR.backupPath, 'utf8') === 'OLD CODEX CONTENT\n');
  } else {
    check('codex 백업 파일 존재', false, codexR.backupPath);
  }
  check('gemini 신규라 백업 없음', gemiR.backupPath === null, gemiR.backupPath);

  // 실제 홈에는 아무것도 안 써졌는지(스크래치 안에만 있어야 함) — 경로가 전부 스크래치 하위인지 확인
  const allInScratch = [path.join(fixtures, 'codex', 'AGENTS.md'), path.join(fixtures, 'gemini', 'GEMINI.md')]
    .every(p => p.startsWith(SCRATCH));
  check('모든 쓰기 경로가 스크래치 하위', allInScratch);
}

console.log(`\n결과: ${pass} pass, ${fail} fail`);
process.exit(fail ? 1 : 0);

'use strict';
// 격리 검증: registry.collectMissing — 로컬 file:// 레지스트리 2개.
//  - regA: 미수집(캐시 없음) → clone 되어야 함(done, 캐시 파일 생성).
//  - regB: 기수집(캐시 있음, 변경 없음) → ls-remote 해시 == 저장 revision → skip(재clone 안 함).
// 원격 clone 금지 — 로컬 git repo를 file:// 로만 접근.

const fs = require('fs');
const path = require('path');
const os = require('os');
const { execFileSync } = require('child_process');

const SCRATCH = process.env.SCRATCH || path.join(os.tmpdir(), 'aad-collect-test');
const PROJ = '/Users/won-yechan/miru_github/agent-dashboard';

fs.rmSync(SCRATCH, { recursive: true, force: true });
fs.mkdirSync(SCRATCH, { recursive: true });

function git(args, cwd) {
  return execFileSync('git', args, { cwd, stdio: ['ignore', 'pipe', 'ignore'] }).toString().trim();
}

// 로컬 bare-ish 소스 repo 하나 생성(SKILL.md 1개 포함). file:// URL과 HEAD 해시 반환.
function makeRepo(name, skillName) {
  const dir = path.join(SCRATCH, 'repos', name);
  fs.mkdirSync(path.join(dir, skillName), { recursive: true });
  fs.writeFileSync(
    path.join(dir, skillName, 'SKILL.md'),
    `---\nname: ${skillName}\ndescription: test skill for ${name}\n---\n\n# ${skillName}\nbody\n`
  );
  git(['init', '-q', '-b', 'main'], dir);
  git(['config', 'user.email', 't@t'], dir);
  git(['config', 'user.name', 't'], dir);
  git(['add', '-A'], dir);
  git(['commit', '-q', '-m', 'init'], dir);
  const head = git(['rev-parse', 'HEAD'], dir);
  return { url: 'file://' + dir, head, dir };
}

const repoA = makeRepo('repoA', 'skill-a');
const repoB = makeRepo('repoB', 'skill-b');

// 격리 환경: canonical(registries.json 위치)·레지스트리 캐시를 스크래치로.
process.env.AAD_CANONICAL = path.join(SCRATCH, 'canonical');
process.env.AAD_REGISTRY_CACHE = path.join(SCRATCH, 'cache');
// 기본 번들 레지스트리는 비우기(빈 파일로 오버라이드) — 78개가 목록에 섞이지 않게.
const emptyDefaults = path.join(SCRATCH, 'default-registries.json');
fs.writeFileSync(emptyDefaults, JSON.stringify({ version: 2, publishers: [] }) + '\n');
process.env.AAD_DEFAULT_REGISTRIES = emptyDefaults;
delete process.env.AAD_MODE;
delete process.env.AAD_ALLOW_REAL;

const registry = require(path.join(PROJ, 'cli', 'registry.js'));

let pass = 0, fail = 0;
function check(label, cond, extra) {
  if (cond) { pass++; console.log('  ✓ ' + label); }
  else { fail++; console.log('  ✗ ' + label + (extra !== undefined ? '  → ' + JSON.stringify(extra) : '')); }
}

(async () => {
  // 두 레지스트리 등록.
  const addA = registry.add(repoA.url, { name: 'repoA' });
  const addB = registry.add(repoB.url, { name: 'repoB' });
  const idA = addA.registry.id;
  const idB = addB.registry.id;

  // regB를 "기수집"으로 만든다: 미리 refresh 해서 캐시 + 저장 revision 생성.
  await registry.refresh(idB);
  const cacheB = registry.registryItemsFile(idB);
  check('사전: regB 캐시 생성됨', fs.existsSync(cacheB));
  const cacheBData1 = JSON.parse(fs.readFileSync(cacheB, 'utf8'));
  check('사전: regB revision == HEAD', cacheBData1.revision === repoB.head, { got: cacheBData1.revision, want: repoB.head });
  const cacheBmtime1 = fs.statSync(cacheB).mtimeMs;
  const cacheBgen1 = cacheBData1.generated_at;

  // regA는 아직 캐시 없음.
  const cacheA = registry.registryItemsFile(idA);
  check('사전: regA 캐시 없음(미수집)', !fs.existsSync(cacheA));

  // collectMissing 실행.
  const status = await registry.collectMissing({ concurrency: 2 });
  check('collect: running=false(종료)', status.running === false, status);
  check('collect: total=2', status.total === 2, status.total);
  check('collect: done=2', status.done === 2, status.done);
  check('collect: failed=0', status.failed === 0, status);

  // regA는 이제 clone되어 캐시 생성.
  check('regA 캐시 생성됨(미수집 → clone)', fs.existsSync(cacheA));
  if (fs.existsSync(cacheA)) {
    const cacheAData = JSON.parse(fs.readFileSync(cacheA, 'utf8'));
    check('regA revision == HEAD', cacheAData.revision === repoA.head, { got: cacheAData.revision });
    check('regA 항목 skill-a 포함', (cacheAData.items || []).some(i => i.name === 'skill-a'), cacheAData.items && cacheAData.items.map(i => i.name));
  }

  // regB는 변경 없음 → skip(재수집 안 함): generated_at이 그대로여야 함.
  const cacheBData2 = JSON.parse(fs.readFileSync(cacheB, 'utf8'));
  check('regB skip(재수집 안 함): generated_at 불변', cacheBData2.generated_at === cacheBgen1, { before: cacheBgen1, after: cacheBData2.generated_at });

  // collectStatus 재조회(방어적 복사 확인).
  const s2 = registry.collectStatus();
  check('collectStatus 재조회 일관', s2.done === 2 && s2.running === false, s2);

  console.log(`\n결과: ${pass} pass, ${fail} fail`);
  process.exit(fail ? 1 : 0);
})().catch((e) => { console.error('테스트 예외:', e); process.exit(1); });

