'use strict';
// 격리 검증: collectMissing 실패 내성 — 나쁜 URL(존재하지 않는 file:// 경로) 1개 + 정상 1개.
// 나쁜 것은 failed+error로 기록하고, 정상 것은 계속 수집되어야 한다(전체 중단 금지).
const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const SCRATCH = process.env.SCRATCH;
const PROJ = '/Users/won-yechan/miru_github/agent-dashboard';
fs.rmSync(SCRATCH, { recursive: true, force: true });
fs.mkdirSync(SCRATCH, { recursive: true });

function git(args, cwd) { return execFileSync('git', args, { cwd, stdio: ['ignore', 'pipe', 'ignore'] }).toString().trim(); }
function makeRepo(name, skillName) {
  const dir = path.join(SCRATCH, 'repos', name);
  fs.mkdirSync(path.join(dir, skillName), { recursive: true });
  fs.writeFileSync(path.join(dir, skillName, 'SKILL.md'), `---\nname: ${skillName}\n---\nbody\n`);
  git(['init', '-q', '-b', 'main'], dir); git(['config', 'user.email', 't@t'], dir); git(['config', 'user.name', 't'], dir);
  git(['add', '-A'], dir); git(['commit', '-q', '-m', 'init'], dir);
  return 'file://' + dir;
}
const goodUrl = makeRepo('good', 'skill-good');
const badUrl = 'file://' + path.join(SCRATCH, 'repos', 'DOES_NOT_EXIST');

process.env.AAD_CANONICAL = path.join(SCRATCH, 'canonical');
process.env.AAD_REGISTRY_CACHE = path.join(SCRATCH, 'cache');
const emptyDefaults = path.join(SCRATCH, 'default-registries.json');
fs.writeFileSync(emptyDefaults, JSON.stringify({ version: 2, publishers: [] }));
process.env.AAD_DEFAULT_REGISTRIES = emptyDefaults;
delete process.env.AAD_MODE; delete process.env.AAD_ALLOW_REAL;

const registry = require(path.join(PROJ, 'cli', 'registry.js'));
let pass = 0, fail = 0;
const check = (l, c, x) => { if (c) { pass++; console.log('  ✓ ' + l); } else { fail++; console.log('  ✗ ' + l + (x !== undefined ? '  → ' + JSON.stringify(x) : '')); } };

(async () => {
  const good = registry.add(goodUrl, { name: 'good' });
  const bad = registry.add(badUrl, { name: 'bad' });
  const status = await registry.collectMissing({ concurrency: 2 });
  check('running=false', status.running === false);
  check('total=2', status.total === 2, status.total);
  check('done=2(둘 다 처리 완료 카운트)', status.done === 2, status.done);
  check('failed=1(나쁜 URL만)', status.failed === 1, status.failed);
  check('errors 1건 + name 포함', status.errors.length === 1 && status.errors[0].name === 'bad', status.errors);
  // 정상 것은 캐시 생성됨(중단되지 않고 계속 수집).
  check('정상 레지스트리 캐시 생성됨', fs.existsSync(registry.registryItemsFile(good.registry.id)));
  console.log(`\n결과: ${pass} pass, ${fail} fail`);
  process.exit(fail ? 1 : 0);
})().catch(e => { console.error(e); process.exit(1); });

